 19→
 20→#include <spdlog/spdlog.h>
 21→
 22→#include <chrono>
 23→#include <memory>
 24→#include <rclcpp/rclcpp.hpp>
 25→
 26→#include "pj_bridge/bridge_server.hpp"
 27→#include "pj_bridge/middleware/websocket_middleware.hpp"
 28→#include "pj_bridge_ros2/ros2_subscription_manager.hpp"
 29→#include "pj_bridge_ros2/ros2_topic_source.hpp"
 30→
 31→int main(int argc, char** argv) {
 32→  rclcpp::init(argc, argv);
 33→
 34→  auto node = std::make_shared<rclcpp::Node>("pj_bridge");
 35→
 36→  RCLCPP_INFO(node->get_logger(), "Starting pj_bridge (ROS2 backend)...");
 37→
 38→  // Declare and get parameters
 39→  node->declare_parameter<int>("port", 8080);
 40→  node->declare_parameter<double>("publish_rate", 50.0);
 41→  node->declare_parameter<double>("session_timeout", 10.0);
 42→  node->declare_parameter<bool>("strip_large_messages", true);
 43→
 44→  int port = node->get_parameter("port").as_int();
 45→  double publish_rate = node->get_parameter("publish_rate").as_double();
 46→  double session_timeout = node->get_parameter("session_timeout").as_double();
 47→  bool strip_large_messages = node->get_parameter("strip_large_messages").as_bool();
 48→
 49→  RCLCPP_INFO(
 50→      node->get_logger(),
 51→      "Configuration: port=%d, publish_rate=%.1f Hz, session_timeout=%.1f s, strip_large_messages=%s", port,
 52→      publish_rate, session_timeout, strip_large_messages ? "true" : "false");
 53→
 54→  try {
 55→    // Create backend components
 56→    auto topic_source = std::make_shared<pj_bridge::Ros2TopicSource>(node);
 57→    auto sub_manager = std::make_shared<pj_bridge::Ros2SubscriptionManager>(node, strip_large_messages);
 58→    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
 59→
 60→    // Create bridge server
 61→    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
 62→
 63→    if (!server.initialize()) {
 64→      RCLCPP_ERROR(node->get_logger(), "Failed to initialize bridge server");
 65→      rclcpp::shutdown();
 66→      return 1;
 67→    }
 68→
 69→    RCLCPP_INFO(node->get_logger(), "Bridge server initialized successfully");
 70→    RCLCPP_INFO(node->get_logger(), "Ready to accept WebSocket connections on port %d", port);
 71→
 72→    // ROS2 timers drive the event loop
 73→    using namespace std::chrono_literals;
 74→
 75→    auto request_timer = node->create_wall_timer(10ms, [&server]() { server.process_requests(); });
 76→
 77→    auto publish_period = std::chrono::duration<double>(1.0 / publish_rate);
 78→    auto publish_timer = node->create_wall_timer(
 79→        std::chrono::duration_cast<std::chrono::nanoseconds>(publish_period),
 80→        [&server]() { server.publish_aggregated_messages(); });
 81→
 82→    auto timeout_timer = node->create_wall_timer(1s, [&server]() { server.check_session_timeouts(); });
 83→
 84→    // Spin until shutdown
 85→    rclcpp::executors::SingleThreadedExecutor executor;
 86→    executor.add_node(node);
 87→
 88→    while (rclcpp::ok()) {
 89→      executor.spin_some(100ms);
 90→    }
 91→
 92→    // Graceful shutdown
 93→    RCLCPP_INFO(node->get_logger(), "Shutting down bridge server...");
 94→
 95→    request_timer->cancel();
 96→    publish_timer->cancel();
 97→    timeout_timer->cancel();
 98→    executor.remove_node(node);
 99→
100→    // Clear the subscription manager callback before server destruction
101→    sub_manager->set_message_callback(nullptr);
102→    sub_manager->unsubscribe_all();
103→    // middleware->shutdown() is handled by BridgeServer destructor
104→
105→    auto [total_messages, total_bytes] = server.get_publish_stats();
106→    RCLCPP_INFO(
107→        node->get_logger(), "Final statistics: %lu messages published, %lu bytes transmitted", total_messages,
108→        total_bytes);
109→
110→    RCLCPP_INFO(node->get_logger(), "Bridge server shutdown complete");
111→
112→  } catch (const std::exception& e) {
113→    RCLCPP_ERROR(node->get_logger(), "Exception in main: %s", e.what());
114→    rclcpp::shutdown();
115→    return 1;
116→  }
117→
118→  rclcpp::shutdown();
119→  return 0;
120→}
