20→#include <spdlog/spdlog.h>
21→
22→#include <CLI/CLI.hpp>
23→#include <string>
24→#include <vector>
25→
26→#include "pj_bridge/middleware/websocket_middleware.hpp"
27→#include "pj_bridge/standalone_event_loop.hpp"
28→#include "pj_bridge_fastdds/fastdds_subscription_manager.hpp"
29→#include "pj_bridge_fastdds/fastdds_topic_source.hpp"
30→
31→int main(int argc, char* argv[]) {
32→  CLI::App app{"pj_bridge eProsima FastDDS Backend"};
33→
34→  std::vector<int32_t> domain_ids;
35→  int port = 8080;
36→  double publish_rate = 50.0;
37→  double session_timeout = 10.0;
38→  std::string log_level = "info";
39→  bool stats_enabled = false;
40→
41→  app.add_option("--domains,-d", domain_ids, "DDS domain IDs")->required()->expected(1, -1);
42→  app.add_option("--port,-p", port, "WebSocket port")->default_val(8080)->check(CLI::Range(1, 65535));
43→  app.add_option("--publish-rate", publish_rate, "Aggregation publish rate in Hz")->default_val(50.0);
44→  app.add_option("--session-timeout", session_timeout, "Session timeout in seconds")->default_val(10.0);
45→  app.add_option("--log-level", log_level, "Log level (trace, debug, info, warn, error)")->default_val("info");
46→  app.add_flag("--stats", stats_enabled, "Print statistics every 5 seconds");
47→
48→  CLI11_PARSE(app, argc, argv);
49→
50→  spdlog::set_level(spdlog::level::from_str(log_level));
51→
52→  spdlog::info("pj_bridge (FastDDS backend) starting...");
53→  spdlog::info("  Domains: {}", fmt::join(domain_ids, ", "));
54→  spdlog::info("  Port: {}", port);
55→  spdlog::info("  Publish rate: {:.1f} Hz", publish_rate);
56→  spdlog::info("  Session timeout: {:.1f} s", session_timeout);
57→
58→  try {
59→    auto topic_source = std::make_shared<pj_bridge::FastDdsTopicSource>(domain_ids);
60→    auto sub_manager = std::make_shared<pj_bridge::FastDdsSubscriptionManager>(*topic_source);
61→    auto middleware = std::make_shared<pj_bridge::WebSocketMiddleware>();
62→
63→    pj_bridge::BridgeServer server(topic_source, sub_manager, middleware, port, session_timeout, publish_rate);
64→
65→    pj_bridge::run_standalone_event_loop(
66→        server, sub_manager, middleware, {port, publish_rate, session_timeout, stats_enabled});
67→  } catch (const std::exception& e) {
68→    spdlog::error("Fatal error: {}", e.what());
69→    return 1;
70→  }
71→
72→  return 0;
73→}
